// ── FUZZY SEARCH FUNCTION USING MEGA INDEX ──────────────────
export function searchMegaIndex(query) {
  const raw = query.toLowerCase().trim();
  const tokens = raw.split(/[\s,._\-/]+/).filter(t => t.length > 1);
  
  const scored = RECIPE_MEGA_INDEX.map(recipe => {
    let score = 0;
    const titleLower = recipe.title.toLowerCase();
    const aliasText = recipe.aliases.join(' ').toLowerCase();
    const tagsText = recipe.tags.join(' ').toLowerCase();
    const ingredientsText = recipe.ingredients.join(' ').toLowerCase();

    tokens.forEach(token => {
      // Direct title match
      if (titleLower.includes(token)) score += 20;
      // Alias match
      if (aliasText.includes(token)) score += 15;
      // Tag match
      if (tagsText.includes(token)) score += 10;
      // Ingredient match
      if (ingredientsText.includes(token)) score += 8;
      // Prefix match (character-by-character) — catches partial words like "kundru"→"kunduri"
      if (token.length >= 4) {
        recipe.aliases.forEach(alias => {
          if (alias.toLowerCase().startsWith(token)) score += 12;
          if (token.startsWith(alias.toLowerCase().substring(0, Math.min(alias.length, token.length)))) score += 6;
        });
        recipe.tags.forEach(tag => {
          if (tag.toLowerCase().startsWith(token)) score += 8;
        });
      }
      
      // Levenshtein on aliases
      recipe.aliases.forEach(alias => {
        const aliasWords = alias.split(/\s+/);
        aliasWords.forEach(aw => {
          const dist = levenshtein(token, aw.toLowerCase());
          if (dist === 0) score += 15;
          else if (dist === 1 && token.length >= 3) score += 10;
          else if (dist === 2 && token.length >= 5) score += 5;
        });
      });

      // LSI synonym expansion
      Object.entries(MEGA_LSI_DICTIONARY).forEach(([key, synonyms]) => {
        const distToKey = levenshtein(token, key.toLowerCase());
        if (distToKey <= 1 && token.length >= 3) {
          synonyms.forEach(syn => {
            if (titleLower.includes(syn) || aliasText.includes(syn)) score += 8;
          });
        }
        synonyms.forEach(syn => {
          const distToSyn = levenshtein(token, syn.toLowerCase());
          if (distToSyn === 0) {
            if (titleLower.includes(key) || aliasText.includes(key)) score += 8;
          }
        });
      });
    });

    return { recipe, score };
  });

  return scored
    .filter(s => s.score > 3)
    .sort((a, b) => b.score - a.score)
    .slice(0, 10)
    .map(s => s.recipe);
}

function levenshtein(a, b) {
  if (a === b) return 0;
  if (!a.length) return b.length;
  if (!b.length) return a.length;
  const m = [];
  for (let i = 0; i <= b.length; i++) { m[i] = [i]; }
  for (let j = 0; j <= a.length; j++) { m[0][j] = j; }
  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      m[i][j] = b[i-1] === a[j-1]
        ? m[i-1][j-1]
        : Math.min(m[i-1][j-1] + 1, m[i][j-1] + 1, m[i-1][j] + 1);
    }
  }
  return m[b.length][a.length];
}
